// Constants
var TAU = 6.283;              // a0_0x72fc0b — Full circle in radians (2π ≈ 6.283)
var GOLDEN_RATIO = 1.618;     // a0_0x40042a — φ, the golden ratio
var SQRT_HALF = 0.707;        // a0_0xc9463b — √(1/2) ≈ 0.707

// Simulation parameters
var params = {                 // a0_0x5e495a
    attractForce: 4000,        // Coulomb-like repulsion numerator
    springCoeff: 0.004,        // Default spring stiffness coefficient
    amplification: 0.92,       // Velocity damping factor per tick (not really "amplification" — see verification below)
    gravityPull: 0.0003,       // Centering gravity strength
    streamLimit: 40,           // Max number of active particles
    streamDecay: 0.04,         // Particle velocity decay rate
    theta: 0.06               // Camera/viewport interpolation smoothing factor
};

// Nodes
var hubNode = {                // a0_0x125afa
    id: 'hub',
    label: 'Hub',
    r: 26,
    x: 400, y: 300,
    vx: 0, vy: 0
};

var alphaNode = {              // a0_0x41c4c4
    id: 'alpha',
    label: 'Alpha',
    r: 16,
    x: 500, y: 200,
    vx: 0, vy: 0
};

var betaNode = {               // a0_0x52d1a3
    id: 'beta',
    label: 'Beta',
    r: 16,
    x: 300, y: 400,
    vx: 0, vy: 0
};

var gammaNode = {              // a0_0x57d4c9
    id: 'gamma',
    label: 'Gamma',
    r: 14,
    x: 250, y: 180,
    vx: 0, vy: 0
};

var deltaNode = {              // a0_0x247912
    id: 'delta',
    label: 'Delta',
    r: 14,
    x: 550, y: 380,
    vx: 0, vy: 0
};

var epsilonNode = {            // a0_0x268672
    id: 'epsilon',
    label: 'Epsilon',
    r: 12,
    x: 350, y: 150,
    vx: 0, vy: 0
};

var nodes = [hubNode, alphaNode, betaNode, gammaNode, deltaNode, epsilonNode];

// Spring/edge definitions
var edges = [                  // a0_0x29c167
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',  rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };       // a0_0x5c885a — current (smoothed)
var cameraTarget = { x: 400, y: 300, zoom: 1 }; // a0_0x2b275f — target

// Particle stream
var particles = [];  // a0_0x4b8ef5
var tickCount = 0;   // a0_0x464d76

// Find a node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Core physics step: repulsion + springs + gravity + damping + integration
function physicsStep() {
    // 1. Coulomb repulsion between all node pairs
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = params.attractForce / (dist * dist); // inverse-square repulsion
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring (Hooke's law) forces along edges
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;

        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || params.springCoeff) * displacement;

        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3. Per-node: centering gravity, damping, and velocity integration
    for (var n = 0; n < nodes.length; n++) {
        // Centering gravity toward (400, 300)
        nodes[n].vx += (400 - nodes[n].x) * params.gravityPull;
        nodes[n].vy += (300 - nodes[n].y) * params.gravityPull;

        // Velocity damping
        nodes[n].vx *= params.amplification;
        nodes[n].vy *= params.amplification;

        // Position integration (Euler)
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a new particle from a random node
function spawnParticle() {
    if (particles.length >= params.streamLimit) return;

    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
    });
}

// Update all particles: move, decay, remove dead
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];

        // Age the particle and remove if expired
        p.age++;
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Velocity decay
        p.vx *= (1 - params.streamDecay * 0.125);
        p.vy *= (1 - params.streamDecay * 0.125);

        // Position integration
        p.x += p.vx;
        p.y += p.vy;
    }
}

// Smooth camera interpolation toward target
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * params.theta;
    camera.y += (cameraTarget.y - camera.y) * params.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * params.theta;
}

// Main tick function
function tick() {
    physicsStep();
    updateParticles();
    updateCamera();

    // Spawn a particle every 3rd tick
    if (tickCount % 3 === 0) spawnParticle();
    tickCount++;
}

// Run at ~60fps (16ms interval)
setInterval(tick, 16);
